import { db, getIsMock } from './firebaseAdmin';

export interface Message {
    role: 'user' | 'assistant' | 'system';
    content: string;
    timestamp: any;
}

// Timeout wrapper for any Firestore operation
function withDbTimeout<T>(promise: Promise<T>, fallback: T, ms = 10000): Promise<T> {
    if (getIsMock()) return Promise.resolve(fallback);
    return Promise.race([
        promise,
        new Promise<T>(resolve => setTimeout(() => {
            console.warn(`[MEMORY] Firestore operation timed out after ${ms}ms, using fallback`);
            resolve(fallback);
        }, ms))
    ]);
}

export async function addMessage(role: 'user' | 'assistant' | 'system', content: string) {
    try {
        await withDbTimeout(
            db.collection('messages').add({
                role,
                content,
                timestamp: new Date()
            }),
            { id: 'timeout-skip' }
        );
    } catch (error) {
        console.error('Firestore addMessage error:', error);
    }
}

export async function getHistory(limit: number = 20): Promise<{ role: string; content: string }[]> {
    if (getIsMock()) return [];
    try {
        const snapshot = await withDbTimeout(
            db.collection('messages')
                .orderBy('timestamp', 'desc')
                .limit(limit)
                .get(),
            { docs: [] }
        );

        const messages = snapshot.docs.map((doc: any) => ({
            role: doc.data().role,
            content: doc.data().content
        }));

        return messages.reverse();
    } catch (error) {
        console.error('Firestore getHistory error:', error);
        return [];
    }
}

export async function clearHistory() {
    if (getIsMock()) return;
    try {
        const snapshot = await withDbTimeout(
            db.collection('messages').get(),
            { docs: [] }
        );
        const batch = db.batch();
        snapshot.docs.forEach((doc: any) => batch.delete(doc.ref));
        await withDbTimeout(batch.commit(), undefined);
    } catch (error) {
        console.error('Firestore clearHistory error:', error);
    }
}
