export function detectIntent(text: string): string {
    const t = text.toLowerCase();
    if (t.includes('haz') || t.includes('crea') || t.includes('codifica') || t.includes('error')) return 'coder';
    if (t.includes('busca') || t.includes('investiga') || t.includes('quien es')) return 'searcher';
    return 'analyst';
}
