import { db, getIsMock } from './firebaseAdmin';
import admin from 'firebase-admin';

// Timeout guard for all Firestore ops
export function dbTimeout<T>(promise: Promise<T>, fallback: T, ms = 10000): Promise<T> {
    if (getIsMock()) return Promise.resolve(fallback);
    return Promise.race([
        promise,
        new Promise<T>(resolve => setTimeout(() => {
            console.warn(`[TOOLS] Firestore operation timed out after ${ms}ms, using fallback`);
            resolve(fallback);
        }, ms))
    ]);
}

// ═══════════════════════════════════════════════════
// LONG-TERM MEMORY (Persistent Knowledge Store)
// ═══════════════════════════════════════════════════

export interface KnowledgeEntry {
    id?: string;
    title: string;
    content: string;
    tags: string[];
    createdAt: Date;
    updatedAt: Date;
    source: 'user' | 'agent' | 'system';
    importance: 'low' | 'medium' | 'high' | 'critical';
}

export async function saveKnowledge(entry: Omit<KnowledgeEntry, 'id' | 'createdAt' | 'updatedAt'>) {
    const now = new Date();
    const ref = await dbTimeout(db.collection('knowledge').add({
        ...entry,
        createdAt: now,
        updatedAt: now
    }), { id: 'timeout' });
    return { id: ref.id, ...entry };
}

export async function searchKnowledge(query: string, limit = 10): Promise<KnowledgeEntry[]> {
    if (getIsMock()) return [];
    const words = query.toLowerCase().split(/\s+/).filter(w => w.length > 2);

    const snapshot = await dbTimeout(db.collection('knowledge')
        .orderBy('updatedAt', 'desc')
        .limit(50)
        .get(), { docs: [] });

    const results = snapshot.docs
        .map((doc: any) => ({ id: doc.id, ...doc.data() } as KnowledgeEntry))
        .filter((entry: any) => {
            const text = `${entry.title} ${entry.content} ${entry.tags.join(' ')}`.toLowerCase();
            return words.some(w => text.includes(w));
        })
        .slice(0, limit);

    return results;
}

export async function getAllKnowledge(limit = 50): Promise<KnowledgeEntry[]> {
    if (getIsMock()) return [];
    const snapshot = await dbTimeout(db.collection('knowledge')
        .orderBy('updatedAt', 'desc')
        .limit(limit)
        .get(), { docs: [] });
    return snapshot.docs.map((doc: any) => ({ id: doc.id, ...doc.data() } as KnowledgeEntry));
}

export async function deleteKnowledge(id: string) {
    await dbTimeout(db.collection('knowledge').doc(id).delete(), undefined);
    return { success: true };
}

export async function updateKnowledge(id: string, updates: Partial<KnowledgeEntry>) {
    await dbTimeout(db.collection('knowledge').doc(id).update({
        ...updates,
        updatedAt: new Date()
    }), undefined);
    return { success: true };
}

// ═══════════════════════════════════════════════════
// CLOUD FILE MANAGER (Firebase Storage alternative using Firestore)
// Store small files/notes as documents for simplicity
// ═══════════════════════════════════════════════════

export interface CloudFile {
    id?: string;
    name: string;
    path: string;
    content: string;
    mimeType: string;
    sizeBytes: number;
    createdAt: Date;
    updatedAt: Date;
}

export async function saveFile(name: string, path: string, content: string, mimeType = 'text/plain') {
    const now = new Date();
    const ref = await dbTimeout(db.collection('files').add({
        name,
        path: path || '/',
        content,
        mimeType,
        sizeBytes: Buffer.byteLength(content, 'utf-8'),
        createdAt: now,
        updatedAt: now
    }), { id: 'timeout' });
    return { id: ref.id, name, path };
}

export async function readFile(fileId: string): Promise<CloudFile | null> {
    const doc = await dbTimeout(db.collection('files').doc(fileId).get(), { id: fileId, exists: false, data: () => ({}) } as any);
    if (!doc.exists) return null;
    return { id: doc.id, ...doc.data() } as CloudFile;
}

export async function listFiles(dirPath = '/'): Promise<Omit<CloudFile, 'content'>[]> {
    if (getIsMock()) return [];
    const snapshot = await dbTimeout(db.collection('files')
        .where('path', '==', dirPath)
        .orderBy('updatedAt', 'desc')
        .get(), { docs: [] });
    return snapshot.docs.map((doc: any) => {
        const data = doc.data();
        return {
            id: doc.id,
            name: data.name,
            path: data.path,
            mimeType: data.mimeType,
            sizeBytes: data.sizeBytes,
            createdAt: data.createdAt?.toDate?.() || data.createdAt,
            updatedAt: data.updatedAt?.toDate?.() || data.updatedAt
        } as Omit<CloudFile, 'content'>;
    });
}

export async function deleteFile(fileId: string) {
    await dbTimeout(db.collection('files').doc(fileId).delete(), undefined);
    return { success: true };
}

export async function updateFile(fileId: string, content: string) {
    await dbTimeout(db.collection('files').doc(fileId).update({
        content,
        sizeBytes: Buffer.byteLength(content, 'utf-8'),
        updatedAt: new Date()
    }), undefined);
    return { success: true };
}

// ═══════════════════════════════════════════════════
// CRON JOBS (Scheduled Tasks stored in Firestore)
// ═══════════════════════════════════════════════════

export interface CronJob {
    id?: string;
    name: string;
    description: string;
    schedule: string;          // e.g. "every 6 hours", "daily at 9am"
    action: string;            // prompt/instruction for the agent
    enabled: boolean;
    lastRun: Date | null;
    nextRun: Date | null;
    createdAt: Date;
    runCount: number;
    lastResult: string | null;
}

export async function createCronJob(job: Omit<CronJob, 'id' | 'createdAt' | 'lastRun' | 'nextRun' | 'runCount' | 'lastResult'>) {
    const now = new Date();
    const nextRun = calculateNextRun(job.schedule, now);
    const ref = await db.collection('cron_jobs').add({
        ...job,
        createdAt: now,
        lastRun: null,
        nextRun,
        runCount: 0,
        lastResult: null
    });
    return { id: ref.id, ...job };
}

export async function listCronJobs(): Promise<CronJob[]> {
    if (getIsMock()) return [];
    const snapshot = await dbTimeout(db.collection('cron_jobs')
        .orderBy('createdAt', 'desc')
        .get(), { docs: [] });
    return snapshot.docs.map((doc: any) => {
        const data = doc.data();
        return {
            id: doc.id,
            ...data,
            createdAt: data.createdAt?.toDate?.() || data.createdAt,
            lastRun: data.lastRun?.toDate?.() || data.lastRun,
            nextRun: data.nextRun?.toDate?.() || data.nextRun
        } as CronJob;
    });
}

export async function toggleCronJob(id: string, enabled: boolean) {
    await db.collection('cron_jobs').doc(id).update({ enabled });
    return { success: true };
}

export async function deleteCronJob(id: string) {
    await dbTimeout(db.collection('cron_jobs').doc(id).delete(), undefined);
    return { success: true };
}

export async function markCronJobRun(id: string, result: string) {
    const now = new Date();
    const doc = await db.collection('cron_jobs').doc(id).get();
    const schedule = doc.data()?.schedule || 'daily';
    await db.collection('cron_jobs').doc(id).update({
        lastRun: now,
        nextRun: calculateNextRun(schedule, now),
        runCount: admin.firestore.FieldValue.increment(1),
        lastResult: result
    });
}

function calculateNextRun(schedule: string, from: Date): Date {
    const next = new Date(from);
    const s = schedule.toLowerCase();
    if (s.includes('minute') || s.includes('1 min')) {
        next.setMinutes(next.getMinutes() + 1);
    } else if (s.includes('5 min')) {
        next.setMinutes(next.getMinutes() + 5);
    } else if (s.includes('15 min')) {
        next.setMinutes(next.getMinutes() + 15);
    } else if (s.includes('30 min') || s.includes('half hour')) {
        next.setMinutes(next.getMinutes() + 30);
    } else if (s.includes('hour') || s.includes('1h')) {
        next.setHours(next.getHours() + 1);
    } else if (s.includes('6 hour') || s.includes('6h')) {
        next.setHours(next.getHours() + 6);
    } else if (s.includes('12 hour') || s.includes('12h')) {
        next.setHours(next.getHours() + 12);
    } else if (s.includes('daily') || s.includes('24h') || s.includes('1 day')) {
        next.setDate(next.getDate() + 1);
    } else if (s.includes('weekly') || s.includes('7 day')) {
        next.setDate(next.getDate() + 7);
    } else {
        // Default: every 6 hours
        next.setHours(next.getHours() + 6);
    }
    return next;
}

// ═══════════════════════════════════════════════════
// SKILLS & MCP INTEGRATION (Autonomous Tooling)
// ═══════════════════════════════════════════════════

export interface Skill {
    id?: string;
    name: string;
    description: string;
    mcpUri: string;
    capabilities: string[];
    installedAt: Date;
    status: 'active' | 'configuring' | 'beta';
}

export async function installSkill(skill: Omit<Skill, 'id' | 'installedAt' | 'status'>) {
    const now = new Date();
    const ref = await db.collection('skills').add({
        ...skill,
        status: 'active',
        installedAt: now
    });
    return { id: ref.id, ...skill };
}

export async function listSkills(): Promise<Skill[]> {
    if (getIsMock()) return [];
    const snapshot = await dbTimeout(db.collection('skills')
        .orderBy('installedAt', 'desc')
        .get(), { docs: [] });
    return snapshot.docs.map((doc: any) => ({
        id: doc.id,
        ...doc.data(),
        installedAt: doc.data().installedAt?.toDate?.() || doc.data().installedAt
    } as Skill));
}

export async function deleteSkill(id: string) {
    await db.collection('skills').doc(id).delete();
    return { success: true };
}

// ═══════════════════════════════════════════════════
// AGENT STATS
// ═══════════════════════════════════════════════════

export async function getAgentStats() {
    if (getIsMock()) return { totalMessages: 0, totalKnowledge: 0, totalFiles: 0, totalCronJobs: 0, totalSkills: 0, activeCronJobs: 0 };
    const [msgSnap, knowSnap, fileSnap, cronSnap, skillSnap] = await Promise.all([
        dbTimeout(db.collection('messages').get(), { size: 0, docs: [] }),
        dbTimeout(db.collection('knowledge').get(), { size: 0, docs: [] }),
        dbTimeout(db.collection('files').get(), { size: 0, docs: [] }),
        dbTimeout(db.collection('cron_jobs').get(), { size: 0, docs: [] }),
        dbTimeout(db.collection('skills').get(), { size: 0, docs: [] })
    ]);
    return {
        totalMessages: msgSnap.size,
        totalKnowledge: knowSnap.size,
        totalFiles: fileSnap.size,
        totalCronJobs: cronSnap.size,
        totalSkills: skillSnap.size,
        activeCronJobs: cronSnap.docs.filter((d: any) => d.data().enabled).length
    };
}
