import fetch from 'node-fetch';

/**
 * AliceLabs Universal Skill Executor
 * This module handles the actual execution of autonomous skills.
 */

interface GitHubRepo {
    full_name: string;
    description: string;
}

interface GitHubSearchResponse {
    items?: GitHubRepo[];
}

export async function executeWebSearch(query: string) {
    try {
        // Using a public search proxy or API (Example with a generic fetch)
        const response = await fetch(`https://api.github.com/search/repositories?q=${encodeURIComponent(query)}&per_page=5`);
        const data = await response.json() as GitHubSearchResponse;

        if (data.items) {
            return data.items.map((i) => `[Repo] ${i.full_name}: ${i.description}`).join('\n');
        }
        return "No results found in GitHub/Web for: " + query;
    } catch (e: unknown) {
        return "Search failed: " + (e as Error).message;
    }
}

export async function executeScraping(url: string) {
    try {
        const response = await fetch(url);
        const text = await response.text();
        return text.substring(0, 1000) + "... [Content Truncated]";
    } catch (e) {
        return "Scraping failed: " + (e as Error).message;
    }
}

export async function callExternalMcp(mcpUri: string, payload: unknown) {
    try {
        // This simulates a call to an MCP server (SSE or StdIO)
        // In a real AliceLabs deployment, this would use the MCP protocol
        console.log(`Calling MCP: ${mcpUri} with ${JSON.stringify(payload)}`);
        return `[MCP Response from ${mcpUri}] Action executed successfully. (Simulated execution for safety/environment limitations)`;
    } catch (e: unknown) {
        return "MCP Call Error: " + (e as Error).message;
    }
}
