/**
 * AliceLabs Security & Firewall Layer
 */

const DANGEROUS_PATTERNS = [
    /SUDO\s+/i,
    /RM\s+-RF/i,
    /FORMAT\s+[A-Z]:/i,
    /DELETE\s+DATABASE/i,
    /DROP\s+TABLE/i,
    /API_KEY\s*=\s*['"][a-z0-9]{20,}/i,
    /SECRET\s*=\s*['"][a-z0-9]{20,}/i
];

export interface SecurityCheckResult {
    safe: boolean;
    reason?: string;
    requiresApproval: boolean;
}

export function auditPrompt(text: string): SecurityCheckResult {
    // Check for jailbreak attempts or leaking secrets
    for (const pattern of DANGEROUS_PATTERNS) {
        if (pattern.test(text)) {
            return { safe: false, reason: "Dangerous command or secret pattern detected.", requiresApproval: true };
        }
    }

    // Check if it's a critical system command
    const criticalKeywords = ['DELETE', 'FORMAT', 'INSTALL_SKILL', 'MCP_CALL'];
    const needsApproval = criticalKeywords.some(kw => text.toUpperCase().includes(kw));

    return { safe: true, requiresApproval: needsApproval };
}

export function sanitizeResponse(text: string): string {
    // Mask API keys if they accidentally leak
    return text.replace(/[a-zA-Z0-9_\-]{24,}/g, (match) => {
        if (match.length > 30) return "[MASKED_SENSITIVE_DATA]";
        return match;
    });
}
