import { HttpsProxyAgent } from 'https-proxy-agent';
import fetch from 'node-fetch';
import * as path from 'path';
import * as fs from 'fs';
import { addMessage, getHistory } from './memory';
import { saveKnowledge, saveFile, createCronJob, searchKnowledge, installSkill } from './tools';
import { executeWebSearch, executeScraping, callExternalMcp } from './skill_executor';
import { auditPrompt, sanitizeResponse } from './security';
import { SUB_AGENTS, detectIntent } from './sub_agents';

interface AIResponse {
    choices?: Array<{ message: { content: string } }>;
    candidates?: Array<{ content: { parts: Array<{ text: string }> } }>;
}

interface GeminiPart {
    text?: string;
    inline_data?: {
        mime_type: string;
        data: string;
    }
}

function loadEnv(): Record<string, string> {
    const cwd = process.cwd();
    let envPath = path.resolve(cwd, '.env');
    if (!fs.existsSync(envPath)) {
        envPath = path.resolve(cwd, '../.env');
    }
    const vars: Record<string, string> = { ...process.env } as Record<string, string>;
    try {
        if (fs.existsSync(envPath)) {
            const content = fs.readFileSync(envPath, 'utf-8');
            content.split('\n').forEach((line: string) => {
                const trimmed = line.trim();
                if (!trimmed || trimmed.startsWith('#')) return;
                const eqIdx = trimmed.indexOf('=');
                if (eqIdx !== -1) {
                    let val = trimmed.substring(eqIdx + 1).trim();
                    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
                        val = val.slice(1, -1);
                    }
                    vars[trimmed.substring(0, eqIdx).trim()] = val;
                }
            });
        }
    } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : String(e);
        console.error(`Env Load Error: ${msg}`);
    }
    return vars;
}

async function fetchWithTimeout(apiUrl: string, apiKey: string, proxyUrl: string | null, payload: Record<string, unknown>, timeoutMs = 8000): Promise<Record<string, unknown> | null> {
    const controller = new AbortController();
    const timer = setTimeout(() => controller.abort(), timeoutMs);

    try {
        const headers: Record<string, string> = { 'Content-Type': 'application/json' };
        if (apiKey) headers['Authorization'] = `Bearer ${apiKey}`;

        const options: Record<string, unknown> = {
            method: 'POST',
            headers,
            body: JSON.stringify(payload),
            signal: controller.signal
        };
        if (proxyUrl) {
            options.agent = new HttpsProxyAgent(proxyUrl);
        }

        const response = await fetch(apiUrl, options as Parameters<typeof fetch>[1]);
        clearTimeout(timer);

        if (!response.ok) {
            console.error(`Status ${response.status}`);
            return null;
        }
        return (await response.json()) as Record<string, unknown>;
    } catch (e: unknown) {
        clearTimeout(timer);
        const msg = e instanceof Error ? e.message : String(e);
        if (msg.includes('abort')) console.error(`Timeout: ${apiUrl}`);
        return null;
    }
}

async function handleToolCalls(text: string): Promise<{ cleanText: string; toolResults: string[] }> {
    let cleanText = text;
    const toolResults: string[] = [];

    // Command patterns
    const memoryRegex = /\[SAVE_MEMORY:\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(low|medium|high|critical)\]/gi;
    const fileRegex = /\[SAVE_FILE:\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(.*?)\]/gi;
    const cronRegex = /\[CREATE_CRON:\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(.*?)\]/gi;
    const skillRegex = /\[INSTALL_SKILL:\s*(.*?)\s*\|\s*(.*?)\s*\|\s*(.*?)\s*\]/gi;
    const searchRegex = /\[WEB_SEARCH:\s*(.*?)\s*\]/gi;
    const scrapRegex = /\[SCRAPE:\s*(.*?)\s*\]/gi;
    const mcpCallRegex = /\[MCP_CALL:\s*(.*?)\s*\|\s*(.*?)\s*\]/gi;

    let match;

    // Execute Memory
    while ((match = memoryRegex.exec(text)) !== null) {
        const [full, content, title, tags, importance] = match;
        await saveKnowledge({
            content,
            title,
            tags: tags.split(','),
            importance: importance as 'low' | 'medium' | 'high' | 'critical',
            source: 'agent'
        }).catch(() => { });
        cleanText = cleanText.replace(full, '');
    }

    // Execute File
    while ((match = fileRegex.exec(text)) !== null) {
        const [full, content, name, fpath] = match;
        await saveFile(name, fpath, content).catch(() => { });
        cleanText = cleanText.replace(full, '');
    }

    // Execute Cron
    while ((match = cronRegex.exec(text)) !== null) {
        const [full, action, schedule, name] = match;
        await createCronJob({ action, schedule, name, description: "AutoTask", enabled: true }).catch(() => { });
        cleanText = cleanText.replace(full, '');
    }

    // Execute Skill Install
    while ((match = skillRegex.exec(text)) !== null) {
        const [full, name, desc, uri] = match;
        await installSkill({ name, description: desc, mcpUri: uri, capabilities: ["auto"] }).catch(() => { });
        cleanText = cleanText.replace(full, '');
    }

    // Execute Web Search
    while ((match = searchRegex.exec(text)) !== null) {
        const [full, query] = match;
        const res = await executeWebSearch(query);
        toolResults.push(`\n🔍 **Search Result:**\n${res}`);
        cleanText = cleanText.replace(full, '');
    }

    // Execute Scraping
    while ((match = scrapRegex.exec(text)) !== null) {
        const [full, url] = match;
        const res = await executeScraping(url);
        toolResults.push(`\n🌐 **Web Content:**\n${res}`);
        cleanText = cleanText.replace(full, '');
    }

    // Execute MCP CALL
    while ((match = mcpCallRegex.exec(text)) !== null) {
        const [full, uri, payload] = match;
        const res = await callExternalMcp(uri, payload);
        toolResults.push(`\n⚙️ **MCP Execution:**\n${res}`);
        cleanText = cleanText.replace(full, '');
    }

    return { cleanText: cleanText.trim(), toolResults };
}

// Helper: race a promise against a timeout
function withTimeout<T>(promise: Promise<T>, ms: number, fallback: T): Promise<T> {
    return Promise.race([
        promise,
        new Promise<T>(resolve => setTimeout(() => resolve(fallback), ms))
    ]);
}

export async function processAiMessage(input: string | any[], imageUrl?: string) {
    const env = loadEnv();
    const chatMessages = typeof input === 'string' ? [{ role: 'user', content: input }] : input;
    const userMessage = chatMessages[chatMessages.length - 1].content;

    // Parallelize DB calls for speed (Max 2.5s)
    let history: Array<{ role: string; content: string }> = [];
    let contextAddition = "";

    try {
        const isPersonalQu = /quien|quién|soy|mi color|sobre mi|dato|repaso|nombre|llamo/i.test(userMessage);
        const searchQuery = isPersonalQu ? "personal perfil " + userMessage : userMessage;

        const results = await Promise.all([
            withTimeout(getHistory(10), 2000, []),
            withTimeout(searchKnowledge(searchQuery, 8), 2500, [])
        ]);

        history = results[0] as any[];
        const hits = results[1] as any[];

        if (hits.length > 0) {
            contextAddition = "\n### DATOS DEL PERFIL/CONOCIMIENTO:\n" + hits.map(h => `- ${h.title}: ${h.content}`).join('\n');
        }
    } catch (e) {
        console.warn("[ALICE] DB fetch failed (continuing without context):", e);
    }

    const wakeWords = ['alice', 'alicia', 'alicelabs', 'labs', 'ale', 'hey', 'oye'];
    const lowerMsg = userMessage.trim().toLowerCase();
    const hasWakeWord = wakeWords.some(ww => lowerMsg.includes(ww));
    const isHot = (history.length > 0) || (chatMessages.length > 1);

    if (!hasWakeWord && !isHot) {
        const dialogueWords = ['donde', 'qué', 'que', 'cómo', 'como', 'por', 'si', 'no', 'hola', 'quiero', 'necesito', 'ayuda', 'dime', 'apis', 'api', 'puedes', 'crear', 'hacer', 'pagina', 'web', 'ecommerce', 'tienda', 'nombre', 'llamo', 'soy', 'mira', 'oye', 'ver', 'haz'];
        const isDialogue = dialogueWords.some(w => lowerMsg.includes(w));
        if (!isDialogue) {
            return { reply: "💤 (Dime **Alice** o **Alicia** para despertarme)", engine: "Standby" };
        }
    }

    // 1. SECURITY AUDIT
    const audit = auditPrompt(userMessage);
    if (!audit.safe) {
        return { reply: `☢️ **Security Alert Blocked:** ${audit.reason}`, engine: "Firewall" };
    }

    // 2. SUB-AGENT SPECIALIZATION & ROUTING
    const intent = detectIntent(userMessage);
    const agent = SUB_AGENTS[intent];

    const sysPrompt = `Eres ${agent.name}. Role: ${agent.role}.
${agent.instructions}

MODALIDAD: ${imageUrl ? "MULTIMODAL (Tienes una imagen adjunta)" : "TEXTO"}.
FULL_SYSTEM_ACCESS_ENABLED:
- Posees capacidades de OCR, escaneo y visión avanzada via Gemini.
- Acceso a Gmail/Drive/Networks via [MCP_CALL].

GOD-MODE MCP CAPABILITIES (TUS HERRAMIENTAS - SE INVISIBLE AL USARLAS):
- [WEB_SEARCH: query], [SCRAPE: url], [MCP_CALL: uri | payload], [INSTALL_SKILL: name | desc | uri]
- [SAVE_MEMORY: content | title | tags | importance] (USO OBLIGATORIO)
- [SAVE_FILE: content | name | path]

💥 REGLAS CRÍTICAS DE MEMORIA Y ALMACENAMIENTO:
1. Siempre que el usuario te diga un dato personal (su nombre, gustos, o te pida guardar algo), DEBES incluir discretamente al final de tu respuesta: [SAVE_MEMORY: El usuario se llama Edison | Perfil de Edison | usuario,perfil | high]. 
2. Si el usuario pide compactar información o descargarla a su disco PC, USA el comando de archivo: [SAVE_FILE: <datos> | backup_memoria.txt | /] inmediatamente.

CONVERSATION_STYLE: Sé asertiva y fluida. No repitas tu nombre. No saludes repetidamente. Actúa.
Context: ${contextAddition}`;

    // 3. BRAIN ROUTING (Resilient multi-key rotation)
    const isRealKey = (k: string | undefined) => k && k.length > 10 && k !== '...' && !k.startsWith('...');

    // Aggregate ALL possible providers
    const providers: any[] = [];

    // Cerebras (Llama 3.3 70B)
    if (isRealKey(env.CEREBRAS_API_KEY)) {
        providers.push({ id: "Cerebras-Llama", apiKey: env.CEREBRAS_API_KEY, url: "https://api.cerebras.ai/v1/chat/completions", model: "llama3.3-70b", type: "openai", tier: 'powerful' });
    }

    // Gemini Rotation (Keys 1-8)
    for (let i = 1; i <= 8; i++) {
        const k = env[`GEMINI_KEY_${i}`];
        if (isRealKey(k)) {
            providers.push({
                id: `Gemini-${i}`,
                apiKey: k,
                url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-pro:generateContent?key=${k}`,
                model: "gemini-1.5-pro",
                type: "gemini_native",
                tier: 'powerful'
            });
        }
    }

    // Mistral Default / Fallback
    const mistralKey = env.MISTRAL_API_KEY || "gzGgFDnH44vj9lVS64TP0xhlZrr2QUdB"; // Use env if possible
    if (isRealKey(mistralKey)) {
        providers.push({ id: "Mistral-Fallback", apiKey: mistralKey, url: "https://api.mistral.ai/v1/chat/completions", model: "mistral-small-latest", type: "openai", tier: 'cheap' });
    }

    console.log(`[ALICE] Engine selection: ${providers.map(p => p.id).join(', ') || 'NOTHING FOUND'}`);

    const preferredTier = agent.model;
    let fallbackOrder = providers;

    // If we want powerful, try powerful first then any
    if (preferredTier === 'powerful') {
        fallbackOrder = [
            ...providers.filter(p => p.tier === 'powerful'),
            ...providers.filter(p => p.tier !== 'powerful')
        ];
    } else if (imageUrl) {
        fallbackOrder = [
            ...providers.filter(p => p.id.startsWith('Gemini')),
            ...providers.filter(p => !p.id.startsWith('Gemini'))
        ];
    }

    console.log(`[ALICE] Attempting sequence: ${fallbackOrder.map(f => f.id).join(' -> ')}`);

    for (const p of fallbackOrder) {
        try {
            let payload: Record<string, unknown>;
            if (p.type === 'gemini_native') {
                const geminiHistory = history.map(h => ({
                    role: h.role === 'user' ? 'user' : 'model',
                    parts: [{ text: h.content }]
                }));
                const contents = [
                    ...geminiHistory,
                    { role: 'user', parts: [{ text: `${sysPrompt}\n\nUSER_MESSAGE: ${userMessage}` }] as GeminiPart[] }
                ];
                if (imageUrl) {
                    const lastPart = contents[contents.length - 1].parts as GeminiPart[];
                    lastPart.push({
                        inline_data: { mime_type: "image/png", data: imageUrl.split(',')[1] }
                    });
                }
                payload = { contents, generationConfig: { maxOutputTokens: 1000, temperature: 0.7 } };
            } else {
                payload = {
                    model: p.model,
                    messages: [{ role: 'system', content: sysPrompt }, ...history, { role: 'user', content: userMessage }],
                    max_tokens: 1500
                };
            }

            console.log(`[ALICE] >>> [${p.id}] Processing request...`);

            // Fix: No Bearer for Gemini URL-based API
            const passKey = p.type === 'gemini_native' ? '' : p.apiKey;

            const data = await fetchWithTimeout(p.url, passKey, null, payload, 30000) as AIResponse | null;
            if (!data) {
                console.warn(`[ALICE] provider ${p.id} returned null/failed`);
                continue;
            }

            let resText = "";
            if (p.type === 'gemini_native') {
                resText = data.candidates?.[0]?.content?.parts?.[0]?.text || "";
            } else {
                resText = data.choices?.[0]?.message?.content || "";
            }

            if (!resText) continue;

            console.log(`[ALICE] ✅ ${p.id} success`);

            // 4. EXECUTION & SANITIZATION
            const { cleanText, toolResults } = await handleToolCalls(resText);
            const rawReply = cleanText + (toolResults.length > 0 ? "\n" + toolResults.join('\n') : "");
            const sanitizedReply = sanitizeResponse(rawReply);

            // Record conversation
            withTimeout(addMessage('user', userMessage), 3000, undefined).catch(() => { });
            withTimeout(addMessage('assistant', sanitizedReply), 3000, undefined).catch(() => { });

            return { reply: sanitizedReply, engine: `${p.id} (${agent.name})` };
        } catch (err: any) {
            console.error(`[ALICE] Error in provider ${p.id}:`, err.message);
            continue;
        }
    }

    return {
        reply: "Error crítico: Mis núcleos de procesamiento no responden. Posible saturación de las API keys o bloqueo de red. Por favor, revisa que tus llaves sean válidas y no tengan restricciones de región.",
        engine: "OFFLINE_CRITICAL"
    };
}
